INSERT OR IGNORE INTO site_settings (key, value) VALUES ('news_event', '{"badge":"2026년 6월 리뷰 이벤트","titleLine1":"후기 남기고","titleLine2":"경품 받아가세요","description":"LG전자 베스트샵 용산점에서 구독·구매 후 네이버 지도 리뷰를 작성하시면 추첨을 통해 경품을 드립니다.","period":"2026.06.01 – 06.30","target":"구독·구매 완료 고객","steps":[{"title":"구독 or 구매 상담","desc":"매장 방문 또는 온라인으로 상담 후 제품을 구독·구매하세요."},{"title":"네이버 지도 리뷰 작성","desc":"LG전자 베스트샵 용산점 네이버 지도 페이지에 별점 5점 + 50자 이상 후기를 남겨주세요."},{"title":"리뷰 캡처 제출","desc":"작성한 리뷰 화면을 캡처하여 카카오톡 채널 또는 상담 신청 폼으로 전송해주세요."},{"title":"경품 수령","desc":"확인 후 영업일 3일 이내 문자로 경품 발송 안내드립니다."}],"prizes":[{"rank":"1등","count":"매월 2명","name":"스타벅스 아메리카노\n10잔 쿠폰","value":"60,000원 상당","highlight":true},{"rank":"2등","count":"매월 5명","name":"편의점 상품권","value":"20,000원","highlight":false},{"rank":"참여 전원","count":"선착순 30명","name":"스타벅스 아메리카노\n1잔 쿠폰","value":"6,000원 상당","highlight":false}],"prizeNote":"※ 당첨자 발표는 매월 초 개별 문자 발송 / 경품은 변경될 수 있습니다.","reviews":[{"id":"nr1","stars":5,"image_key":"","content":"상담부터 설치까지 꼼꼼하게 챙겨주셔서 정말 만족스러웠어요. 제품도 생각보다 훨씬 조용하고 공간 활용이 좋네요. 매니저님이 색상 조합까지 같이 고민해줘서 인테리어에도 딱 맞게 선택했습니다.","name":"김*현","product":"LG 디오스 오브제컬렉션 냉장고","date":"2026.05.18","sort_order":0},{"id":"nr2","stars":5,"image_key":"","content":"구독 서비스가 이렇게 편할 줄 몰랐어요. 설치도 빠르고 관리까지 해준다니 너무 좋아요. 용산점 매니저분이 실제 사용 팁도 알려주셔서 처음 사용하는 데 전혀 어렵지 않았습니다.","name":"박*은","product":"LG 워시타워 렌탈 가전 구독","date":"2026.05.12","sort_order":1},{"id":"nr3","stars":5,"image_key":"","content":"혼자 사는데 거실에 두기 딱 좋은 사이즈예요. 가격 대비 화질이 정말 좋고, 배터리로 어디서나 볼 수 있어서 활용도가 높아요. 매장에서 직접 비교하고 구매할 수 있어서 좋았습니다.","name":"이*준","product":"LG 스탠바이미 2 렌탈 가전 구독","date":"2026.04.29","sort_order":2}]}');
